package claude

import (
	"context"
	"fmt"
	"math"
	"time"

	"github.com/easel/fizeau/internal/harnesses"
	"github.com/easel/fizeau/internal/harnesses/ptyquota"
	"github.com/easel/fizeau/internal/pty/cassette"
	"github.com/easel/fizeau/internal/pty/session"
)

type quotaPTYOptions struct {
	binary      string
	args        []string
	workdir     string
	env         []string
	cassetteDir string
}

type QuotaPTYOption func(*quotaPTYOptions)

func WithQuotaPTYCommand(binary string, args ...string) QuotaPTYOption {
	return func(opts *quotaPTYOptions) {
		opts.binary = binary
		opts.args = append([]string(nil), args...)
	}
}

func WithQuotaPTYWorkdir(workdir string) QuotaPTYOption {
	return func(opts *quotaPTYOptions) {
		opts.workdir = workdir
	}
}

func WithQuotaPTYEnv(env ...string) QuotaPTYOption {
	return func(opts *quotaPTYOptions) {
		opts.env = append([]string(nil), env...)
	}
}

func WithQuotaPTYCassetteDir(dir string) QuotaPTYOption {
	return func(opts *quotaPTYOptions) {
		opts.cassetteDir = dir
	}
}

func ReadClaudeQuotaViaPTY(timeout time.Duration, opts ...QuotaPTYOption) ([]harnesses.QuotaWindow, *harnesses.AccountInfo, error) {
	windows, account, _, err := captureClaudeQuotaViaPTY(context.Background(), timeout, opts...)
	return windows, account, err
}

func RefreshClaudeQuotaViaPTY(timeout time.Duration, opts ...QuotaPTYOption) (ClaudeQuotaSnapshot, error) {
	windows, account, _, err := captureClaudeQuotaViaPTY(context.Background(), timeout, opts...)
	if err != nil {
		return ClaudeQuotaSnapshot{}, err
	}
	return claudeQuotaSnapshotFromWindows(windows, account), nil
}

func ReadClaudeQuotaFromCassette(dir string) ([]harnesses.QuotaWindow, *harnesses.AccountInfo, error) {
	reader, err := cassette.Open(dir)
	if err != nil {
		return nil, nil, err
	}
	text := reader.Final().FinalText
	if text == "" {
		frames := reader.Frames()
		if len(frames) > 0 {
			text = stringsJoinLines(frames[len(frames)-1].Text)
		}
	}
	windows, account := parseClaudeUsageOutput(text)
	if len(windows) == 0 {
		return nil, account, fmt.Errorf("no quota windows found in claude quota cassette")
	}
	if err := validateClaudeQuotaEvidence(windows, account); err != nil {
		return nil, account, fmt.Errorf("incomplete claude quota cassette: %w", err)
	}
	return windows, account, nil
}

func captureClaudeQuotaViaPTY(ctx context.Context, timeout time.Duration, opts ...QuotaPTYOption) ([]harnesses.QuotaWindow, *harnesses.AccountInfo, ptyquota.Result, error) {
	cfg := quotaPTYOptions{binary: "claude"}
	for _, opt := range opts {
		if opt != nil {
			opt(&cfg)
		}
	}
	var windows []harnesses.QuotaWindow
	var account *harnesses.AccountInfo
	result, err := ptyquota.Run(ctx, ptyquota.Config{
		HarnessName:  "claude",
		Binary:       cfg.binary,
		Args:         cfg.args,
		Workdir:      cfg.workdir,
		Env:          cfg.env,
		Command:      "/usage\r",
		ReadyMarkers: []string{"❯", "> "},
		DoneWhen:     claudeUsageComplete,
		Timeout:      timeout,
		Size:         session.Size{Rows: 50, Cols: 220},
		CassetteDir:  cfg.cassetteDir,
		Quota: func(text string) (cassette.QuotaRecord, error) {
			windows, account = parseClaudeUsageOutput(text)
			if len(windows) == 0 {
				return cassette.QuotaRecord{}, fmt.Errorf("no quota windows found in claude /usage output")
			}
			if err := validateClaudeQuotaEvidence(windows, account); err != nil {
				return cassette.QuotaRecord{}, fmt.Errorf("incomplete claude /usage output: %w", err)
			}
			return quotaRecord(windows, map[string]any{"plan_type": accountPlan(account)}), nil
		},
	})
	if err != nil {
		return nil, nil, result, err
	}
	if len(windows) == 0 {
		windows, account = parseClaudeUsageOutput(result.Text)
	}
	if len(windows) == 0 {
		return nil, account, result, fmt.Errorf("no quota windows found in claude /usage output")
	}
	if err := validateClaudeQuotaEvidence(windows, account); err != nil {
		return nil, account, result, fmt.Errorf("incomplete claude /usage output: %w", err)
	}
	return windows, account, result, nil
}

func claudeQuotaSnapshotFromWindows(windows []harnesses.QuotaWindow, account *harnesses.AccountInfo) ClaudeQuotaSnapshot {
	fiveHourUsed := usedPercentFor(windows, "session")
	weeklyUsed := usedPercentFor(windows, "weekly-all")
	if weeklyUsed < 0 {
		weeklyUsed = usedPercentFor(windows, "weekly-sonnet")
	}
	return ClaudeQuotaSnapshot{
		CapturedAt:        time.Now().UTC(),
		FiveHourLimit:     100,
		FiveHourRemaining: remainingPercent(fiveHourUsed),
		WeeklyLimit:       100,
		WeeklyRemaining:   remainingPercent(weeklyUsed),
		Windows:           append([]harnesses.QuotaWindow(nil), windows...),
		Source:            "pty",
		Account:           account,
	}
}

func usedPercentFor(windows []harnesses.QuotaWindow, limitID string) float64 {
	for _, window := range windows {
		if window.LimitID == limitID {
			return window.UsedPercent
		}
	}
	return -1
}

func hasQuotaWindow(windows []harnesses.QuotaWindow, limitID string) bool {
	return usedPercentFor(windows, limitID) >= 0
}

func claudeUsageComplete(text string) bool {
	windows, _ := parseClaudeUsageOutput(text)
	return hasQuotaWindow(windows, "session") && (hasQuotaWindow(windows, "weekly-all") || hasQuotaWindow(windows, "weekly-sonnet"))
}

func validateClaudeQuotaEvidence(windows []harnesses.QuotaWindow, account *harnesses.AccountInfo) error {
	if accountPlan(account) == "" {
		return fmt.Errorf("missing account plan")
	}
	if !hasQuotaWindow(windows, "session") {
		return fmt.Errorf("missing session window")
	}
	if !hasQuotaWindow(windows, "weekly-all") && !hasQuotaWindow(windows, "weekly-sonnet") {
		return fmt.Errorf("missing weekly window")
	}
	return nil
}

func remainingPercent(used float64) int {
	if used < 0 {
		return 0
	}
	remaining := int(math.Round(100 - used))
	if remaining < 0 {
		return 0
	}
	if remaining > 100 {
		return 100
	}
	return remaining
}

func quotaRecord(windows []harnesses.QuotaWindow, metadata map[string]any) cassette.QuotaRecord {
	records := make([]map[string]any, 0, len(windows))
	for _, window := range windows {
		records = append(records, map[string]any{
			"name":           window.Name,
			"limit_id":       window.LimitID,
			"window_minutes": window.WindowMinutes,
			"used_percent":   window.UsedPercent,
			"resets_at":      window.ResetsAt,
			"state":          window.State,
		})
	}
	accountClass, _ := metadata["plan_type"].(string)
	return cassette.QuotaRecord{
		Source:            "pty",
		Status:            string(ptyquota.StatusOK),
		CapturedAt:        time.Now().UTC().Format(time.RFC3339),
		FreshnessWindow:   DefaultClaudeQuotaStaleAfter.String(),
		StalenessBehavior: "stale quota evidence keeps Claude out of automatic routing and is treated as limited",
		AccountClass:      accountClass,
		Windows:           records,
		Metadata:          metadata,
	}
}

func accountPlan(account *harnesses.AccountInfo) string {
	if account == nil {
		return ""
	}
	return account.PlanType
}

func stringsJoinLines(lines []string) string {
	out := ""
	for i, line := range lines {
		if i > 0 {
			out += "\n"
		}
		out += line
	}
	return out
}

package claude

import (
	"context"
	"fmt"
	"os/exec"
	"regexp"
	"strings"
	"time"

	"github.com/easel/fizeau/internal/harnesses"
	"github.com/easel/fizeau/internal/harnesses/ptyquota"
	"github.com/easel/fizeau/internal/pty/cassette"
	"github.com/easel/fizeau/internal/pty/session"
)

const ClaudeModelDiscoveryFreshnessWindow = 24 * time.Hour

var (
	claudeFullModelPattern         = regexp.MustCompile(`\bclaude-[a-z0-9][a-z0-9._-]*\b`)
	claudeFullFamilyVersionPattern = regexp.MustCompile(`\bclaude-(sonnet|opus|haiku)-([0-9]+)[.-]([0-9]{1,2})(?:\b|-)`)
	claudeFamilyVersionPattern     = regexp.MustCompile(`\b(?:claude\s+)?(sonnet|opus|haiku)\s+([0-9]+(?:[.-][0-9]+){0,2})\b`)
	claudeAliasPattern             = regexp.MustCompile(`(?m)(?:^|[\s'"])(sonnet|opus|haiku)(?:$|[\s'"])`)
	claudeEffortPattern            = regexp.MustCompile(`--effort\s+<level>.*\(([^)]*)\)`)
)

func DefaultClaudeModelDiscovery() harnesses.ModelDiscoverySnapshot {
	return harnesses.ModelDiscoverySnapshot{
		CapturedAt:      time.Now().UTC(),
		Models:          []string{"sonnet", "sonnet-4.6", "opus", "opus-4.7", "claude-sonnet-4-6"},
		ReasoningLevels: []string{"low", "medium", "high", "xhigh", "max"},
		Source:          "cli-help:claude",
		FreshnessWindow: ClaudeModelDiscoveryFreshnessWindow.String(),
		Detail:          "claude --help documents --model aliases/full IDs and --effort levels; authenticated PTY /model evidence refreshes family alias versions",
	}
}

func ReadClaudeModelDiscoveryViaPTY(timeout time.Duration, opts ...QuotaPTYOption) (harnesses.ModelDiscoverySnapshot, error) {
	cfg := quotaPTYOptions{binary: "claude"}
	for _, opt := range opts {
		if opt != nil {
			opt(&cfg)
		}
	}
	var snapshot harnesses.ModelDiscoverySnapshot
	_, err := ptyquota.Run(context.Background(), ptyquota.Config{
		HarnessName:  "claude",
		Binary:       cfg.binary,
		Args:         cfg.args,
		Workdir:      cfg.workdir,
		Env:          cfg.env,
		Command:      "/model\r",
		ReadyMarkers: []string{"❯", "> "},
		DoneWhen:     claudeModelDiscoveryComplete,
		Timeout:      timeout,
		Size:         session.Size{Rows: 50, Cols: 220},
		CassetteDir:  cfg.cassetteDir,
		Discovery: func(text string) (cassette.DiscoveryRecord, error) {
			snapshot = claudeDiscoveryFromText(text, "pty")
			if len(snapshot.Models) == 0 {
				return cassette.DiscoveryRecord{}, fmt.Errorf("no models found in claude /model output")
			}
			return discoveryRecord(snapshot), nil
		},
	})
	if err != nil {
		return harnesses.ModelDiscoverySnapshot{}, err
	}
	if len(snapshot.Models) == 0 {
		return harnesses.ModelDiscoverySnapshot{}, fmt.Errorf("no models found in claude /model output")
	}
	return snapshot, nil
}

func ReadClaudeModelDiscoveryFromCassette(dir string) (harnesses.ModelDiscoverySnapshot, error) {
	reader, err := cassette.Open(dir)
	if err != nil {
		return harnesses.ModelDiscoverySnapshot{}, err
	}
	if rec := reader.Discovery(); rec != nil && len(rec.Models) > 0 {
		return snapshotFromDiscoveryRecord(*rec), nil
	}
	text := reader.Final().FinalText
	if text == "" {
		frames := reader.Frames()
		if len(frames) > 0 {
			text = strings.Join(frames[len(frames)-1].Text, "\n")
		}
	}
	snapshot := claudeDiscoveryFromText(text, "cassette")
	if len(snapshot.Models) == 0 {
		return harnesses.ModelDiscoverySnapshot{}, fmt.Errorf("no models found in claude model cassette")
	}
	return snapshot, nil
}

func ReadClaudeReasoningFromHelp(ctx context.Context, binary string, args ...string) ([]string, error) {
	if binary == "" {
		binary = "claude"
	}
	if len(args) == 0 {
		args = []string{"--help"}
	}
	cmd := exec.CommandContext(ctx, binary, args...)
	out, err := cmd.CombinedOutput()
	if err != nil {
		return nil, fmt.Errorf("claude help: %w", err)
	}
	levels := parseClaudeReasoningLevels(string(out))
	if len(levels) == 0 {
		return nil, fmt.Errorf("claude help did not expose --effort levels")
	}
	return levels, nil
}

func claudeModelDiscoveryComplete(text string) bool {
	return len(parseClaudeModels(text)) > 0
}

func claudeDiscoveryFromText(text, source string) harnesses.ModelDiscoverySnapshot {
	snapshot := DefaultClaudeModelDiscovery()
	if source != "" {
		snapshot.Source = source
	}
	if models := parseClaudeModels(text); len(models) > 0 {
		snapshot.Models = models
	}
	if levels := parseClaudeReasoningLevels(text); len(levels) > 0 {
		snapshot.ReasoningLevels = levels
	}
	return snapshot
}

func parseClaudeModels(text string) []string {
	text = stripANSI(strings.ReplaceAll(text, "\r\n", "\n"))
	lower := strings.ToLower(text)
	models := uniqueMatches(claudeFullModelPattern.FindAllString(lower, -1))
	for _, match := range claudeFullFamilyVersionPattern.FindAllStringSubmatch(lower, -1) {
		if len(match) > 3 {
			models = appendUniqueString(models, match[1]+"-"+match[2]+"."+match[3])
		}
	}
	for _, match := range claudeFamilyVersionPattern.FindAllStringSubmatch(lower, -1) {
		if len(match) > 2 {
			models = appendUniqueString(models, match[1]+"-"+strings.ReplaceAll(match[2], "-", "."))
		}
	}
	for _, match := range claudeAliasPattern.FindAllStringSubmatch(lower, -1) {
		if len(match) > 1 {
			models = appendUniqueString(models, match[1])
		}
	}
	return models
}

func ResolveClaudeFamilyAlias(model string, snapshot harnesses.ModelDiscoverySnapshot) string {
	family := strings.ToLower(strings.TrimSpace(model))
	if family != "sonnet" && family != "opus" && family != "haiku" {
		return model
	}
	if resolved := latestClaudeFamilyVersion(family, snapshot.Models); resolved != "" {
		return resolved
	}
	return model
}

func latestClaudeFamilyVersion(family string, models []string) string {
	prefix := family + "-"
	best := ""
	var bestParts []int
	for _, model := range models {
		model = strings.ToLower(strings.TrimSpace(model))
		if !strings.HasPrefix(model, prefix) {
			continue
		}
		parts, ok := parseClaudeVersionParts(strings.TrimPrefix(model, prefix))
		if !ok {
			continue
		}
		if best == "" || compareVersionParts(parts, bestParts) > 0 {
			best = model
			bestParts = parts
		}
	}
	return best
}

func parseClaudeVersionParts(version string) ([]int, bool) {
	version = strings.ReplaceAll(version, "-", ".")
	raw := strings.Split(version, ".")
	if len(raw) == 0 {
		return nil, false
	}
	parts := make([]int, 0, len(raw))
	for _, part := range raw {
		if part == "" {
			return nil, false
		}
		n := 0
		for _, r := range part {
			if r < '0' || r > '9' {
				return nil, false
			}
			n = n*10 + int(r-'0')
		}
		parts = append(parts, n)
	}
	return parts, true
}

func compareVersionParts(a, b []int) int {
	n := len(a)
	if len(b) > n {
		n = len(b)
	}
	for i := 0; i < n; i++ {
		av, bv := 0, 0
		if i < len(a) {
			av = a[i]
		}
		if i < len(b) {
			bv = b[i]
		}
		if av > bv {
			return 1
		}
		if av < bv {
			return -1
		}
	}
	return 0
}

func parseClaudeReasoningLevels(text string) []string {
	text = stripANSI(strings.ReplaceAll(text, "\n", " "))
	m := claudeEffortPattern.FindStringSubmatch(text)
	if len(m) < 2 {
		return nil
	}
	parts := strings.Split(m[1], ",")
	out := make([]string, 0, len(parts))
	for _, part := range parts {
		out = appendUniqueString(out, strings.TrimSpace(part))
	}
	return out
}

func discoveryRecord(snapshot harnesses.ModelDiscoverySnapshot) cassette.DiscoveryRecord {
	return cassette.DiscoveryRecord{
		Source:            snapshot.Source,
		Status:            string(ptyquota.StatusOK),
		Models:            append([]string(nil), snapshot.Models...),
		ReasoningLevels:   append([]string(nil), snapshot.ReasoningLevels...),
		CapturedAt:        snapshot.CapturedAt.UTC().Format(time.RFC3339),
		FreshnessWindow:   snapshot.FreshnessWindow,
		StalenessBehavior: "stale model discovery evidence requires authenticated PTY refresh before capability promotion",
		Metadata:          map[string]any{"detail": snapshot.Detail},
	}
}

package claude

import (
	"context"
	"strings"
	"time"

	"golang.org/x/sync/singleflight"

	"github.com/easel/fizeau/internal/harnesses"
)

// claudeQuotaFreshness is the constant freshness window for claude quota
// evidence. Mirrors DefaultClaudeQuotaStaleAfter (kept as a separate name
// so the CONTRACT-004 method has a stable, contract-named constant).
const claudeQuotaFreshness = DefaultClaudeQuotaStaleAfter

// claudeAccountFreshness is the constant freshness window for claude
// account evidence. Claude embeds account info in its quota probe so the
// account refresh cadence matches quota.
const claudeAccountFreshness = DefaultClaudeQuotaStaleAfter

// supportedLimitIDs is the stable public set of Windows[].LimitID values
// claude's quota probe emits. Mirrored in doc.go for human readers.
var supportedLimitIDs = []string{
	"session",
	"weekly-all",
	"weekly-sonnet",
	"extra",
}

// supportedAliases is the stable public set of family aliases
// ResolveModelAlias recognizes. Mirrored in doc.go for human readers.
var supportedAliases = []string{"sonnet", "opus", "haiku"}

// refreshGroup serializes concurrent RefreshQuota / RefreshAccount calls
// across all *Runner instances. Per CONTRACT-004 invariant #6 Runners are
// stateless wrappers — sharing the singleflight group at package scope
// keeps single-flight semantics correct when callers construct fresh
// runner instances per call (which the dispatcher does today).
var refreshGroup singleflight.Group

// QuotaProbeFunc is the signature of the PTY-quota probe that
// Runner.RefreshQuota delegates to. Exposing it as a named type keeps
// the SetCaptureForTest seam decoupled from the internal ptyquota
// package; the test seam discards the ptyquota.Result that the live
// probe returns.
type QuotaProbeFunc func(ctx context.Context, timeout time.Duration, opts ...QuotaPTYOption) ([]harnesses.QuotaWindow, *harnesses.AccountInfo, error)

// captureQuotaProbe is the live PTY probe used by RefreshQuota. It is a
// package-level variable so tests can swap it via SetCaptureForTest
// without spawning the claude binary. The default delegates to
// captureClaudeQuotaViaPTY and discards the ptyquota.Result.
var captureQuotaProbe QuotaProbeFunc = func(ctx context.Context, timeout time.Duration, opts ...QuotaPTYOption) ([]harnesses.QuotaWindow, *harnesses.AccountInfo, error) {
	windows, account, _, err := captureClaudeQuotaViaPTY(ctx, timeout, opts...)
	return windows, account, err
}

// SetCaptureForTest swaps the package-level PTY probe used by
// Runner.RefreshQuota and returns a restore function. Production code
// MUST NOT call this — it exists so service-level tests can inject
// deterministic PTY responses while exercising the real cache I/O
// inside Runner.refreshQuotaLocked. The call also forgets any
// in-flight RefreshQuota cohort so the next caller runs a fresh
// single-flight execution against the new probe instead of piggybacking
// on a prior test's probe.
func SetCaptureForTest(fn QuotaProbeFunc) func() {
	prev := captureQuotaProbe
	captureQuotaProbe = fn
	refreshGroup.Forget("claude:refresh-quota")
	return func() {
		captureQuotaProbe = prev
		refreshGroup.Forget("claude:refresh-quota")
	}
}

// QuotaStatus implements harnesses.QuotaHarness. It reads the cached
// snapshot owned by this harness and projects it onto QuotaStatus. A
// missing or undecodable cache is reported as State=QuotaUnavailable on
// a valid QuotaStatus value (no error) per CONTRACT-004 §"Errors are
// reserved for call failure."
func (r *Runner) QuotaStatus(ctx context.Context, now time.Time) (harnesses.QuotaStatus, error) {
	if err := ctx.Err(); err != nil {
		return harnesses.QuotaStatus{}, err
	}
	snap, ok := ReadClaudeQuota()
	if !ok || snap == nil {
		return harnesses.QuotaStatus{
			Source:            "cache",
			State:             harnesses.QuotaUnavailable,
			RoutingPreference: harnesses.RoutingPreferenceUnknown,
			Reason:            "no cached snapshot",
		}, nil
	}
	return claudeQuotaStatusFromSnapshot(snap, now), nil
}

// RefreshQuota implements harnesses.QuotaHarness. It probes the claude
// CLI via PTY unconditionally and persists the result through the
// harness's owned cache. Single-flight per harness: concurrent callers
// share one cohort and observe the just-written cached state. Probe
// failure (binary missing, PTY error, parse failure) is reported as
// State=QuotaUnavailable on a valid QuotaStatus value, not as an error.
func (r *Runner) RefreshQuota(ctx context.Context) (harnesses.QuotaStatus, error) {
	if err := ctx.Err(); err != nil {
		return harnesses.QuotaStatus{}, err
	}
	v, err, _ := refreshGroup.Do("claude:refresh-quota", func() (any, error) {
		return r.refreshQuotaLocked(ctx), nil
	})
	if err != nil {
		return harnesses.QuotaStatus{}, err
	}
	return v.(harnesses.QuotaStatus), nil
}

// refreshQuotaLocked is the single-flight critical section. It probes
// PTY, writes the cache on success, and returns the projected status.
// Probe failure is folded into State=QuotaUnavailable.
func (r *Runner) refreshQuotaLocked(ctx context.Context) harnesses.QuotaStatus {
	now := time.Now()
	timeout := claudeQuotaFreshness
	if deadline, ok := ctx.Deadline(); ok {
		remaining := time.Until(deadline)
		if remaining > 0 && remaining < timeout {
			timeout = remaining
		}
	}
	var opts []QuotaPTYOption
	if r.Binary != "" {
		opts = append(opts, WithQuotaPTYCommand(r.Binary))
	}
	windows, account, err := captureQuotaProbe(ctx, timeout, opts...)
	if err != nil {
		state := harnesses.QuotaUnavailable
		reason := err.Error()
		if strings.Contains(strings.ToLower(reason), "not found in path") {
			state = harnesses.QuotaUnauthenticated
		}
		return harnesses.QuotaStatus{
			Source:            "pty",
			CapturedAt:        now.UTC(),
			State:             state,
			RoutingPreference: harnesses.RoutingPreferenceUnknown,
			Reason:            reason,
		}
	}
	snap := claudeQuotaSnapshotFromWindows(windows, account)
	if path, pathErr := ClaudeQuotaCachePath(); pathErr == nil {
		_ = WriteClaudeQuota(path, snap)
	}
	return claudeQuotaStatusFromSnapshot(&snap, now)
}

// QuotaFreshness implements harnesses.QuotaHarness.
func (r *Runner) QuotaFreshness() time.Duration {
	return claudeQuotaFreshness
}

// SupportedLimitIDs implements harnesses.QuotaHarness.
func (r *Runner) SupportedLimitIDs() []string {
	return append([]string(nil), supportedLimitIDs...)
}

// AccountStatus implements harnesses.AccountHarness. Claude embeds
// account/plan info inside its quota probe, so this method projects the
// quota cache's Account field onto AccountSnapshot.
func (r *Runner) AccountStatus(ctx context.Context, now time.Time) (harnesses.AccountSnapshot, error) {
	if err := ctx.Err(); err != nil {
		return harnesses.AccountSnapshot{}, err
	}
	snap, ok := ReadClaudeQuota()
	if !ok || snap == nil {
		return harnesses.AccountSnapshot{Source: "cache"}, nil
	}
	return claudeAccountSnapshotFromQuotaSnapshot(snap, now), nil
}

// RefreshAccount implements harnesses.AccountHarness by driving the
// quota probe (which carries account evidence) and projecting the
// resulting cached snapshot onto AccountSnapshot.
func (r *Runner) RefreshAccount(ctx context.Context) (harnesses.AccountSnapshot, error) {
	if _, err := r.RefreshQuota(ctx); err != nil {
		return harnesses.AccountSnapshot{}, err
	}
	return r.AccountStatus(ctx, time.Now())
}

// AccountFreshness implements harnesses.AccountHarness.
func (r *Runner) AccountFreshness() time.Duration {
	return claudeAccountFreshness
}

// DefaultModelSnapshot implements harnesses.ModelDiscoveryHarness.
func (r *Runner) DefaultModelSnapshot() harnesses.ModelDiscoverySnapshot {
	return DefaultClaudeModelDiscovery()
}

// ResolveModelAlias implements harnesses.ModelDiscoveryHarness. Returns
// harnesses.ErrAliasNotResolvable when the supplied family is not a
// recognized claude alias or when the supplied discovery snapshot has
// no concrete model matching the family.
func (r *Runner) ResolveModelAlias(family string, snapshot harnesses.ModelDiscoverySnapshot) (string, error) {
	normalized := strings.ToLower(strings.TrimSpace(family))
	if !isSupportedClaudeAlias(normalized) {
		return "", harnesses.ErrAliasNotResolvable
	}
	resolved := ResolveClaudeFamilyAlias(normalized, snapshot)
	if resolved == "" {
		return "", harnesses.ErrAliasNotResolvable
	}
	return resolved, nil
}

// SupportedAliases implements harnesses.ModelDiscoveryHarness.
func (r *Runner) SupportedAliases() []string {
	return append([]string(nil), supportedAliases...)
}

func isSupportedClaudeAlias(family string) bool {
	for _, a := range supportedAliases {
		if a == family {
			return true
		}
	}
	return false
}

// claudeQuotaStatusFromSnapshot projects the per-harness snapshot onto
// harnesses.QuotaStatus, deriving State and RoutingPreference via the
// existing DecideClaudeQuotaRouting helper so today's "PreferClaude +
// freshness" semantics map cleanly onto CONTRACT-004's RoutingPreference
// enum.
func claudeQuotaStatusFromSnapshot(snap *ClaudeQuotaSnapshot, now time.Time) harnesses.QuotaStatus {
	decision := DecideClaudeQuotaRouting(snap, now, claudeQuotaFreshness)
	pref, state := mapClaudeRoutingPreference(decision)
	status := harnesses.QuotaStatus{
		Source:            snap.Source,
		CapturedAt:        snap.CapturedAt,
		Fresh:             decision.Fresh,
		Age:               decision.Age,
		State:             state,
		Windows:           append([]harnesses.QuotaWindow(nil), snap.Windows...),
		RoutingPreference: pref,
		Reason:            quotaReasonForProjection(decision, state),
	}
	if snap.Account != nil {
		acct := claudeAccountSnapshotFromQuotaSnapshot(snap, now)
		status.Account = &acct
	}
	return status
}

// quotaReasonForProjection trims the routing decision's diagnostic
// reason so QuotaStatus.Reason carries information only when it adds
// value beyond the State enum. The trivial QuotaOK success path
// ("fresh snapshot has headroom") is suppressed so the public Status
// string matches the contract-003 fixture (bare "ok"). All non-OK
// states keep the decision reason because it surfaces why the state is
// not ok (stale snapshot, incomplete account, exhausted window).
func quotaReasonForProjection(decision ClaudeQuotaRoutingDecision, state harnesses.QuotaStateValue) string {
	if state == harnesses.QuotaOK {
		return ""
	}
	return decision.Reason
}

// mapClaudeRoutingPreference translates today's PreferClaude+freshness
// decision into the CONTRACT-004 (RoutingPreference, QuotaStateValue)
// pair. Legacy semantics: missing snapshot ⇒ Unavailable/Unknown;
// stale ⇒ Stale/Blocked ("assume limited"); fresh+PreferClaude ⇒
// OK/Available; fresh+!PreferClaude ⇒ Blocked/Blocked.
func mapClaudeRoutingPreference(d ClaudeQuotaRoutingDecision) (harnesses.RoutingPreference, harnesses.QuotaStateValue) {
	if !d.SnapshotPresent {
		return harnesses.RoutingPreferenceUnknown, harnesses.QuotaUnavailable
	}
	if !d.Fresh {
		return harnesses.RoutingPreferenceBlocked, harnesses.QuotaStale
	}
	if d.PreferClaude {
		return harnesses.RoutingPreferenceAvailable, harnesses.QuotaOK
	}
	return harnesses.RoutingPreferenceBlocked, harnesses.QuotaBlocked
}

// claudeAccountSnapshotFromQuotaSnapshot derives an AccountSnapshot from
// the quota cache's embedded Account field. Plan-type "unknown" (written
// by MarkClaudeQuotaExhaustedFromMessage on runtime errors) is reported
// as unauthenticated evidence rather than positive authentication.
func claudeAccountSnapshotFromQuotaSnapshot(snap *ClaudeQuotaSnapshot, now time.Time) harnesses.AccountSnapshot {
	out := harnesses.AccountSnapshot{
		Source:     "cache",
		CapturedAt: snap.CapturedAt,
		Fresh:      IsClaudeQuotaFresh(snap, now, claudeAccountFreshness),
	}
	if snap.Account == nil {
		return out
	}
	plan := strings.TrimSpace(snap.Account.PlanType)
	out.PlanType = plan
	out.Email = snap.Account.Email
	out.OrgName = snap.Account.OrgName
	switch {
	case plan == "" || strings.EqualFold(plan, "unknown"):
		out.Unauthenticated = true
	default:
		out.Authenticated = true
	}
	return out
}

// Compile-time interface satisfaction.
var (
	_ harnesses.Harness               = (*Runner)(nil)
	_ harnesses.QuotaHarness          = (*Runner)(nil)
	_ harnesses.AccountHarness        = (*Runner)(nil)
	_ harnesses.ModelDiscoveryHarness = (*Runner)(nil)
)

package runtimesignals

import (
	"context"
	"encoding/json"
	"net/http"
	"sync"
	"time"

	"github.com/easel/fizeau/internal/discoverycache"
	"github.com/easel/fizeau/internal/harnesses"
	claudecache "github.com/easel/fizeau/internal/harnesses/claude"
	codexcache "github.com/easel/fizeau/internal/harnesses/codex"
	geminiharness "github.com/easel/fizeau/internal/harnesses/gemini"
	"github.com/easel/fizeau/internal/provider/quotaheaders"
)

const (
	// RuntimeTTL is the default cache TTL for runtime signals (ADR-012 §2).
	RuntimeTTL = 5 * time.Minute
	// RuntimeRefreshDeadline bounds how long a runtime signal refresh may take.
	RuntimeRefreshDeadline = 5 * time.Second

	defaultWindowSize = 100
	aliveCheckTimeout = 3 * time.Second
)

// Store is the per-process in-memory state for runtime signal collection.
// It holds per-provider latency windows and the most recently observed
// rate-limit header signals. All methods are safe for concurrent use.
type Store struct {
	mu        sync.RWMutex
	latencies map[string]*LatencyWindow
	headers   *headerStore
}

// CollectInput describes the provider identity needed to assemble a runtime
// signal. Type controls the collection path; BaseURL is used by local
// providers for the live /v1/models check.
type CollectInput struct {
	Type    string
	BaseURL string
}

// NewStore creates an empty Store ready for use.
func NewStore() *Store {
	return &Store{
		latencies: make(map[string]*LatencyWindow),
		headers:   newHeaderStore(),
	}
}

// DefaultStore is the process-singleton Store used by the package-level
// RecordResponse and Collect functions.
var DefaultStore = NewStore()

// RecordResponse records an HTTP response observation for a provider using the
// DefaultStore. providerType controls which header parser is applied
// ("openrouter", "anthropic", or any other value for the OpenAI parser).
func RecordResponse(provider string, h http.Header, latency time.Duration, providerType string) {
	DefaultStore.RecordResponse(provider, h, latency, providerType)
}

// RecordResponse records an HTTP response observation. It updates both the
// latency window and the header signal store for the named provider.
func (s *Store) RecordResponse(provider string, h http.Header, latency time.Duration, providerType string) {
	win := s.latencyWindow(provider)
	win.Record(latency)

	if h != nil {
		now := time.Now()
		var sig quotaheaders.Signal
		switch providerType {
		case "openrouter":
			sig = quotaheaders.ParseOpenRouter(h, now)
		case "anthropic":
			sig = quotaheaders.ParseAnthropic(h, now)
		default:
			sig = quotaheaders.ParseOpenAI(h, now)
		}
		s.headers.record(provider, sig)
	}
}

// Collect assembles a runtime Signal for the named provider using
// DefaultStore.
func Collect(ctx context.Context, providerName string, cfg CollectInput) (Signal, error) {
	return DefaultStore.Collect(ctx, providerName, cfg)
}

// Collect assembles a runtime Signal for providerName. The cfg.Type field
// controls which collection path is used:
//
//   - "claude"       → existing internal/harnesses/claude/quota_cache.go
//   - "codex"        → existing internal/harnesses/codex/quota_cache.go
//   - "gemini"       → existing internal/harnesses/gemini/quota_cache.go
//   - "openrouter"   → most recently recorded rate-limit headers (OpenRouter parser)
//   - "openai", "anthropic", and unknown HTTP types → rate-limit headers
//   - local types    → HTTP GET /v1/models alive check (no quota concept)
func (s *Store) Collect(ctx context.Context, providerName string, cfg CollectInput) (Signal, error) {
	sig := Signal{
		Provider:   providerName,
		Status:     StatusUnknown,
		RecordedAt: time.Now().UTC(),
	}

	s.mu.RLock()
	win := s.latencies[providerName]
	s.mu.RUnlock()
	if win != nil {
		sig.RecentP50Latency = win.P50()
	}

	providerType := cfg.Type

	switch providerType {
	case "claude":
		collectClaudeSignal(&sig)
	case "codex":
		collectCodexSignal(&sig)
	case "gemini":
		collectGeminiSignal(&sig)
	case "ds4", "llama-server", "omlx", "lmstudio", "lucebox", "vllm", "rapid-mlx", "ollama":
		collectLocalSignal(ctx, cfg.BaseURL, &sig)
	default:
		s.collectHeaderSignal(providerName, &sig)
	}

	return sig, nil
}

// CacheSource returns the discoverycache.Source descriptor for a provider's
// runtime signal. The file path resolves to runtime/<provider>.json.
func CacheSource(providerName string) discoverycache.Source {
	return discoverycache.Source{
		Tier:            "runtime",
		Name:            providerName,
		TTL:             RuntimeTTL,
		RefreshDeadline: RuntimeRefreshDeadline,
	}
}

// Write serializes sig and stores it in M1's runtime cache tier. The cache
// file lands at <cache.Root>/runtime/<sig.Provider>.json.
func Write(cache *discoverycache.Cache, sig Signal) error {
	data, err := json.Marshal(sig)
	if err != nil {
		return err
	}
	src := CacheSource(sig.Provider)
	return cache.Refresh(src, func(_ context.Context) ([]byte, error) {
		return data, nil
	})
}

// ReadCached reads a Signal from M1's runtime cache for providerName.
// Returns (nil, false) when the entry is absent or cannot be decoded.
func ReadCached(cache *discoverycache.Cache, providerName string) (*Signal, bool) {
	src := CacheSource(providerName)
	result, err := cache.Read(src)
	if err != nil || result.Data == nil {
		return nil, false
	}
	var sig Signal
	if err := json.Unmarshal(result.Data, &sig); err != nil {
		return nil, false
	}
	return &sig, true
}

// ---- per-provider-type collectors -------------------------------------------

func collectClaudeSignal(sig *Signal) {
	snap, ok := claudecache.ReadClaudeQuota()
	if !ok || snap == nil {
		return // StatusUnknown
	}
	if claudecache.ClaudeQuotaSnapshotAge(snap, time.Now()) > claudecache.DefaultClaudeQuotaStaleAfter {
		return // StatusUnknown; snapshot is stale
	}
	if snap.WeeklyRemaining <= 0 || snap.FiveHourRemaining <= 0 {
		sig.Status = StatusExhausted
		zero := 0
		sig.QuotaRemaining = &zero
		return
	}
	sig.Status = StatusAvailable
	rem := snap.FiveHourRemaining
	sig.QuotaRemaining = &rem
}

func collectCodexSignal(sig *Signal) {
	r := &codexcache.Runner{}
	status, err := r.QuotaStatus(context.Background(), time.Now())
	if err != nil {
		return
	}
	switch status.State {
	case harnesses.QuotaOK:
		sig.Status = StatusAvailable
	case harnesses.QuotaBlocked:
		sig.Status = StatusExhausted
		zero := 0
		sig.QuotaRemaining = &zero
		// QuotaUnavailable and QuotaStale both leave Status as StatusUnknown
	}
}

func collectGeminiSignal(sig *Signal) {
	r := &geminiharness.Runner{}
	status, err := r.QuotaStatus(context.Background(), time.Now())
	if err != nil {
		return
	}
	switch status.State {
	case harnesses.QuotaOK:
		sig.Status = StatusAvailable
	case harnesses.QuotaBlocked:
		sig.Status = StatusExhausted
		zero := 0
		sig.QuotaRemaining = &zero
		// QuotaUnavailable and QuotaStale both leave Status as StatusUnknown
	}
}

// collectHeaderSignal reads the most recently recorded rate-limit header signal
// for the provider and populates sig accordingly.
func (s *Store) collectHeaderSignal(providerName string, sig *Signal) {
	hSig, ok := s.headers.get(providerName)
	if !ok {
		return // StatusUnknown; no headers observed yet
	}
	exhausted, retryAfter := hSig.IsExhausted(time.Now())
	if exhausted {
		sig.Status = StatusExhausted
		zero := 0
		sig.QuotaRemaining = &zero
		if !retryAfter.IsZero() {
			t := retryAfter
			sig.QuotaResetAt = &t
		}
		return
	}
	sig.Status = StatusAvailable
	switch {
	case hSig.RemainingRequests >= 0:
		rem := int(hSig.RemainingRequests)
		sig.QuotaRemaining = &rem
	case hSig.RemainingTokens >= 0:
		rem := int(hSig.RemainingTokens)
		sig.QuotaRemaining = &rem
	}
	if !hSig.ResetTime.IsZero() {
		t := hSig.ResetTime
		sig.QuotaResetAt = &t
	}
}

// collectLocalSignal performs an HTTP GET /v1/models alive check for local
// providers. Local providers have no quota concept; only StatusAvailable vs
// StatusDegraded is determined.
func collectLocalSignal(ctx context.Context, baseURL string, sig *Signal) {
	if baseURL == "" {
		return // StatusUnknown
	}
	timeoutCtx, cancel := context.WithTimeout(ctx, aliveCheckTimeout)
	defer cancel()

	checkURL := baseURL + "/v1/models"
	req, err := http.NewRequestWithContext(timeoutCtx, http.MethodGet, checkURL, nil) // #nosec G107
	if err != nil {
		return // StatusUnknown; bad URL
	}
	resp, err := (&http.Client{}).Do(req)
	if err != nil {
		sig.Status = StatusDegraded
		sig.LastErrorMsg = err.Error()
		now := time.Now().UTC()
		sig.LastErrorAt = &now
		return
	}
	defer resp.Body.Close()

	if resp.StatusCode >= 200 && resp.StatusCode < 300 {
		sig.Status = StatusAvailable
		now := time.Now().UTC()
		sig.LastSuccessAt = &now
	} else {
		sig.Status = StatusDegraded
	}
}

// ---- internal helpers -------------------------------------------------------

func (s *Store) latencyWindow(provider string) *LatencyWindow {
	s.mu.RLock()
	win, ok := s.latencies[provider]
	s.mu.RUnlock()
	if ok {
		return win
	}
	s.mu.Lock()
	defer s.mu.Unlock()
	if win, ok = s.latencies[provider]; ok {
		return win
	}
	win = NewLatencyWindow(defaultWindowSize)
	s.latencies[provider] = win
	return win
}

